using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,m,x,w=0;
pair<bool,string> a[MAXN];
signed main(void)
{
	cin>>n>>m;
	FOR(i,0,n-1)
	{
		cin>>a[i].fst>>a[i].snd;
	}
	FOR(i,1,m)
	{
		bool c;
		int b;
		cin>>c>>b;
		if(!a[w].fst&&!c)w=w+n-b;
        else if(!a[w].fst&&c)w=w+b;
        else if(a[w].fst&&!c)w=w+b;
        else if(a[w].fst&&c)w=w+n-b;
		w%=n;
	}
	cout<<a[w].snd;
    return false;
}
